What is the output of the following code snippet considering operator precedence?
```cpp
#include <iostream>
using namespace std;
int main() {
    int x = 10, y = 20, z = 5;
    int res = x > y ? x : y > z ? y : z;
    cout << res;
    return 0;
}
```

